# 输入获取
tmp = list(map(int, input().split()))
c = tmp[0]
b = tmp[1]
arr = tmp[2:]


# 判断是否有效
def classify(a):
    s = hex(a)[2:]  # hex方法会将十进制转为0x开头的16进制数,这里去除0x前缀

    if len(s) % 2 != 0:
        s = "0" + s  # 补足0

    sumV = 0
    for i in range(0, len(s) - 1, 2):
        sumV += int(s[i:i + 2], 16)

    t = sumV % b

    if t < c:
        return t
    else:
        return -1


# 算法入口
def getResult():
    count = {}

    for t in map(classify, arr):
        if t != -1:
            if count.get(t) is None:
                count[t] = 1
            else:
                count[t] += 1

    return max(count.values())


# 算法调用
print(getResult())
